INSERT INTO faqs (id, question, answer, detail_answer, order_index) VALUES
(1, '음성 녹음만 업로드 할 수 있나요?', '현재는 음성 녹음만 업로드 가능해요.', '포에버 서비스가 초기 단계인 만큼 아쉽게도 추가하지 못한 기능이 많이 있어요.\n필요한 기능을 알려주신다면 반영할 수 있도록 최선을 다하겠습니다 💪', 1),
(2, '이별 후에는 장례식장을 찾아볼 수 없는 건가요?', '네, 현재는 이별 전 또는 긴급 대처 모드 단계에만 제공하고 있어요.', '대신 이별 후에는 이용하셨던 업체에 대한 후기를 다른 반려인들과 공유할 수 있어요. 이별 후 홈화면에서 후기를 보내주시면 향후 업데이트 때 노출 예정이에요!', 2),
(3, '이별 전에 별자리 추모관을 보여주는 이유가 무엇인가요?', '비슷한 경험을 가진 타인과 위로를 나누면 하는 취지에서 시작했어요.', '심리학에 ''예기 비탄''이라는 개념이 있어요.\n아직 일어나지 않은 이별임에도 일상에 지장이 갈 정도로 힘들어하시는 분들이 많으신데요.\n\n이별 후에도 이렇게 위로를 받을 수 있구나.\n모두 힘든 시절을 겪었구나. 와 같이 포에버 서비스를 통해 조금이라도 위안을 드리고 싶었어요.', 3),
(4, '반려동물 프로필을 함께 관리하는 사람 간 권한이 어떻게 다른가요?', '같은 반려동물이라도 ''오너''와 ''게스트'' 간 권한이 달라요.', '- 오너(Owner): 프로필을 최초로 생성한 분입니다.\n''발자국 남기기'' 미션의 최종 확정, 음성 녹음 기능의 실행 및 저장, 그리고 초대코드를 발급하여 가족이나 지인을 관리할 수 있는 전권력을 가져요.\n\n- 게스트(Guest): 초대코드를 통해 입장한 분입니다.\n공유된 반려동물의 추억을 함께 열람하고 일부 기록에 참여할 수 있으나, 음성 녹음은 불가능하며 미리 살펴보기 단계에서 게스트가 확인하는 절차는 앱 사용 진척도에 저장되지 않고, 오너의 사용만 Home 화면 진척도에 포함되어 반영이 됩니다. (내용은 모두 동일하게 확인 할 수 있어요!)', 4),
(5, '회원 탈퇴를 하면 제가 남긴 추억들은 어떻게 되나요?', '회원 탈퇴 신청 시, 소중한 데이터를 보호하기 위해 5일간의 유예 기간을 두고 있어요!', '소중한 개인정보 보관을 위해 5일의 유예 기간이 지나면 모든 정보는 복구가 불가능한 방법으로 영구 파기됩니다.\n\n단, 법령(통신비밀보호법)에 따라 접속 로그 등의 최소한의 기록은 3개월간 보관된 후 삭제됩니다.\n\n만일, 누군가가 악의적으로 프로필 정보 등을 수정하였다면 아래 이메일로 문의주세요!\n\n5일 이내 벌어진 일이라면 복구해드릴 수 있어요.', 5),
(6, '''발자국 남기기'' 미션의 질문들을 건너뛴 채로 ''긴급 대처 모드''를 눌렀어요. 다시 답변하거나 이전 단계로 돌아갈 수 있나요?', '네, 당연히 가능합니다.', '대표 문항을 건너뛰었더라도 언제든지\n[설정 > 내 정보 관리 > 프로필 수정] 메뉴 하단에서\n이별 전 단계로 돌아가 미션을 수행하거나 답변을 수정할 수 있어요.\n\n포에버는 보호자님이 마음의 준비가 되었을 때 언제든 추억을 기록할 수 있도록 열려 있습니다.', 6),
(7, '제가 녹음한 음성 메시지를 다른 사람도 들을 수 있나요?', '오너가 녹음한 음성은 초대코드로 연결된 게스트만 들을 수 있어요.', '즉, 우리 아이 프로필을 관리하는 사용자끼리만 공유가 가능해요.\n\n다만, 이 과정에서 감정적인 문제 등이 발생할 수 있으니, 귀중한 음성 정보 공유는 신중하게 결정해주세요!', 7),
(8, '앱을 통해 소개받은 장례 업체 이용 중 사고가 발생했어요.', '포에버는 보호자님께 장례 업체를 연결해 드리는 역할이에요.', '실제 장례 서비스 계약은 보호자님과 해당 업체 간에 성립되는 것이므로, 예약·결제·서비스 품질·사고 등과 관련된 모든 책임은 장례 업체와 이용자 본인에게 있습니다.\n\n포에버는 실제 계약의 당사자가 아니므로 보상 책임에서 제외되니 참고해주세요!\n\n이러한 일이 발생하면 다른 분들이 피해받지 않도록 포에버에 솔직한 후기를 작성해주세요.', 8)
